"""Impacto espacio-temporal de eventos sobre la intensidad predicha."""

from __future__ import annotations

import math
from datetime import datetime
from typing import Any
from zoneinfo import ZoneInfo

TZ = ZoneInfo("Europe/Madrid")


def _parse_dt(value: str) -> datetime:
    return datetime.fromisoformat(value.replace("Z", "+00:00")).astimezone(TZ)


def haversine_m(lat1: float, lon1: float, lat2: float, lon2: float) -> float:
    r = 6_371_000
    p1, p2 = math.radians(lat1), math.radians(lat2)
    dphi = math.radians(lat2 - lat1)
    dlmb = math.radians(lon2 - lon1)
    a = math.sin(dphi / 2) ** 2 + math.cos(p1) * math.cos(p2) * math.sin(dlmb / 2) ** 2
    return 2 * r * math.asin(math.sqrt(a))


def temporal_factor(
    event_start: datetime,
    event_end: datetime,
    at: datetime,
    factor_max: float,
    ramp_hours: float = 2.0,
    decay_hours: float = 1.0,
) -> float:
    """Curva: rampa antes del evento, pico durante, decaimiento después."""
    if at < event_start:
        ramp_start = event_start.timestamp() - ramp_hours * 3600
        if at.timestamp() <= ramp_start:
            return 1.0
        t = (at.timestamp() - ramp_start) / (event_start.timestamp() - ramp_start)
        return 1.0 + t * (factor_max - 1.0)
    if at <= event_end:
        return factor_max
    decay_end = event_end.timestamp() + decay_hours * 3600
    if at.timestamp() >= decay_end:
        return 1.0
    t = (at.timestamp() - event_end.timestamp()) / (decay_end - event_end.timestamp())
    return factor_max - t * (factor_max - 1.0)


def spatial_factor(dist_m: float, radio_m: float) -> float:
    if radio_m <= 0:
        return 0.0
    if dist_m >= radio_m:
        return 0.0
    return 1.0 - (dist_m / radio_m) ** 2


def event_multiplier(
    event: dict[str, Any],
    lat: float,
    lon: float,
    at: datetime,
) -> float:
    """Multiplicador >= 1.0 para un punto (lat, lon) en el instante `at`."""
    try:
        start = _parse_dt(event["inicio"])
        end = _parse_dt(event.get("fin", event["inicio"]))
    except (KeyError, ValueError):
        return 1.0

    factor_max = float(event.get("factor_max", 1.2))
    radio = float(event.get("radio_metros", 300))
    elat = float(event["lat"])
    elon = float(event["lon"])

    t_factor = temporal_factor(start, end, at, factor_max)
    if t_factor <= 1.0:
        return 1.0

    dist = haversine_m(lat, lon, elat, elon)
    s_factor = spatial_factor(dist, radio)
    if s_factor <= 0:
        return 1.0

    return 1.0 + (t_factor - 1.0) * s_factor


def apply_events_to_intensity(
    intensidad: float,
    lat: float,
    lon: float,
    at: datetime,
    events: list[dict[str, Any]],
) -> float:
    """Combina multiplicadores de todos los eventos activos (producto)."""
    mult = 1.0
    for ev in events:
        mult *= event_multiplier(ev, lat, lon, at)
    return intensidad * mult

"""Tramos de vía afectados por eventos urbanos (distancia a LineString)."""

from __future__ import annotations

from typing import Any

from .geo_utils import geometry_coords, point_to_linestring_m


def tramos_affected_by_event(
    tramo_features: list[dict[str, Any]],
    lat: float,
    lon: float,
    radio_metros: float,
) -> list[str]:
    """IDs de tramos cuya geometría está dentro del radio del evento."""
    affected: list[str] = []
    for feat in tramo_features:
        props = feat.get("properties") or {}
        tid = str(props.get("idtramo", ""))
        coords = geometry_coords(feat.get("geometry"))
        if not coords or not tid:
            continue
        if point_to_linestring_m(lat, lon, coords) <= radio_metros:
            affected.append(tid)
    return affected


def tramos_affected_by_events(
    tramo_features: list[dict[str, Any]],
    events: list[dict[str, Any]],
) -> list[str]:
    """Unión de tramos afectados por varios eventos."""
    seen: set[str] = set()
    out: list[str] = []
    for ev in events:
        try:
            lat = float(ev["lat"])
            lon = float(ev["lon"])
            radio = float(ev.get("radio_metros", 300))
        except (KeyError, TypeError, ValueError):
            continue
        for tid in tramos_affected_by_event(tramo_features, lat, lon, radio):
            if tid not in seen:
                seen.add(tid)
                out.append(tid)
    return out

"""Carga y filtrado de eventos urbanos."""

from __future__ import annotations

from datetime import date, datetime
from functools import lru_cache
from typing import Any
from zoneinfo import ZoneInfo

from .data_loader import load_city_events_raw

TZ = ZoneInfo("Europe/Madrid")


def _enrich_event(ev: dict[str, Any]) -> dict[str, Any]:
    return dict(ev)


@lru_cache
def load_city_events() -> list[dict[str, Any]]:
    return load_city_events_raw()


def list_events(
    from_date: date | None = None,
    to_date: date | None = None,
) -> list[dict[str, Any]]:
    events = load_city_events()
    if from_date is None and to_date is None:
        return [_enrich_event(ev) for ev in events]

    out = []
    for ev in events:
        try:
            start = datetime.fromisoformat(ev["inicio"].replace("Z", "+00:00")).date()
            end = datetime.fromisoformat(ev.get("fin", ev["inicio"]).replace("Z", "+00:00")).date()
        except (KeyError, ValueError):
            continue
        if from_date and end < from_date:
            continue
        if to_date and start > to_date:
            continue
        out.append(_enrich_event(ev))
    return out


def events_at(
    target_date: date,
    hora: int,
    events: list[dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    """Eventos que pueden influir en la hora dada del día."""
    pool = events if events is not None else load_city_events()
    at = datetime(target_date.year, target_date.month, target_date.day, hora, 0, tzinfo=TZ)
    active = []
    for ev in pool:
        try:
            start = datetime.fromisoformat(ev["inicio"].replace("Z", "+00:00")).astimezone(TZ)
            end = datetime.fromisoformat(ev.get("fin", ev["inicio"]).replace("Z", "+00:00")).astimezone(TZ)
        except (KeyError, ValueError):
            continue
        ramp_start = start.timestamp() - 2 * 3600
        decay_end = end.timestamp() + 2 * 3600
        ts = at.timestamp()
        if ramp_start <= ts <= decay_end:
            active.append(ev)
    return active

"""Utilidades geográficas ligeras (sin dependencias GIS)."""

from __future__ import annotations

import math
from typing import Any


def haversine_m(lat1: float, lon1: float, lat2: float, lon2: float) -> float:
    r = 6_371_000.0
    p1, p2 = math.radians(lat1), math.radians(lat2)
    dlat = math.radians(lat2 - lat1)
    dlon = math.radians(lon2 - lon1)
    a = math.sin(dlat / 2) ** 2 + math.cos(p1) * math.cos(p2) * math.sin(dlon / 2) ** 2
    return 2 * r * math.asin(math.sqrt(min(1.0, a)))


def line_centroid(coords: list[list[float]]) -> tuple[float, float]:
    if not coords:
        return 0.0, 0.0
    lons = [c[0] for c in coords]
    lats = [c[1] for c in coords]
    return sum(lats) / len(lats), sum(lons) / len(lons)


def point_to_linestring_m(lat: float, lon: float, coords: list[list[float]]) -> float:
    """Distancia mínima aproximada (m) de un punto a una LineString."""
    if len(coords) < 2:
        if coords:
            return haversine_m(lat, lon, coords[0][1], coords[0][0])
        return float("inf")
    best = float("inf")
    for i in range(len(coords) - 1):
        lon1, lat1 = coords[i][0], coords[i][1]
        lon2, lat2 = coords[i + 1][0], coords[i + 1][1]
        for t in (0.0, 0.25, 0.5, 0.75, 1.0):
            plat = lat1 + t * (lat2 - lat1)
            plon = lon1 + t * (lon2 - lon1)
            best = min(best, haversine_m(lat, lon, plat, plon))
    return best


def geometry_coords(geometry: dict[str, Any] | None) -> list[list[float]]:
    if not geometry:
        return []
    gtype = geometry.get("type")
    coords = geometry.get("coordinates")
    if gtype == "LineString" and isinstance(coords, list):
        return coords
    return []

from __future__ import annotations

import json
from collections import defaultdict
from datetime import datetime, timezone
from pathlib import Path
from typing import Any


DUPLICATE_WINDOW_SECONDS = 900


def utc_now() -> datetime:
    return datetime.now(timezone.utc)


def iso_utc(dt: datetime) -> str:
    return dt.isoformat().replace("+00:00", "Z")


class DataArchiver:
    def __init__(self, project_root: Path, data_root: str) -> None:
        self.base_dir = (project_root / data_root).resolve()
        self.current_status: dict[str, dict[str, Any]] = {}
        self.last_sha1_seen_at: dict[str, datetime] = {}

    def _parse_iso_ts(self, value: Any) -> datetime | None:
        if value is None:
            return None

        text = str(value).strip()
        if not text:
            return None

        if text.endswith("Z"):
            text = text[:-1] + "+00:00"

        try:
            parsed = datetime.fromisoformat(text)
        except ValueError:
            return None

        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)

    def _missing_fields_count(self, event: dict[str, Any]) -> int:
        required = [
            "record_key",
            "station_id",
            "charger_id",
            "connector_id",
            "status",
            "message_type",
            "payload_sha1",
            "payload_json",
        ]
        missing = 0
        for key in required:
            value = event.get(key)
            if value in (None, "", [], {}):
                missing += 1
        return missing

    def _compute_derived(self, event: dict[str, Any], received_dt: datetime) -> dict[str, Any]:
        record_key = [credential removed] or "")
        previous = self.current_status.get(record_key) if record_key else None

        source_dt = self._parse_iso_ts(event.get("source_ts"))
        event_lag_seconds = None
        if source_dt is not None:
            event_lag_seconds = round((received_dt - source_dt).total_seconds(), 3)

        prev_status = previous.get("status") if previous else None
        current_status = event.get("status")
        status_changed = previous is not None and prev_status != current_status

        prev_status_duration_seconds = None
        if previous is not None:
            prev_received_at = self._parse_iso_ts(previous.get("received_at"))
            if prev_received_at is not None:
                prev_status_duration_seconds = round((received_dt - prev_received_at).total_seconds(), 3)

        payload_sha1 = str(event.get("payload_sha1") or "")
        prev_sha1_seen_at = self.last_sha1_seen_at.get(payload_sha1)
        is_duplicate_sha1 = False
        if payload_sha1 and prev_sha1_seen_at is not None:
            delta = (received_dt - prev_sha1_seen_at).total_seconds()
            is_duplicate_sha1 = delta <= DUPLICATE_WINDOW_SECONDS

        if payload_sha1:
            self.last_sha1_seen_at[payload_sha1] = received_dt

        return {
            "event_lag_seconds": event_lag_seconds,
            "status_changed": status_changed,
            "prev_status": prev_status,
            "prev_status_duration_seconds": prev_status_duration_seconds,
            "is_duplicate_sha1": is_duplicate_sha1,
            "missing_fields_count": self._missing_fields_count(event),
        }

    def _raw_file_path(self, dt: datetime) -> Path:
        return self.base_dir / "raw" / dt.strftime("%Y/%m/%d") / dt.strftime("events_%Y-%m-%d_%H.jsonl")

    def _snapshot_file_path(self, dt: datetime) -> Path:
        name = dt.strftime("snapshot_%Y-%m-%d_%H-%M.json")
        return self.base_dir / "snapshots" / dt.strftime("%Y/%m/%d") / name

    def append_records(self, records: list[dict[str, Any]]) -> int:
        by_file: dict[Path, list[dict[str, Any]]] = defaultdict(list)

        for record in records:
            received_dt = utc_now()
            event = {
                "received_at": iso_utc(received_dt),
                "source_ts": record.get("source_ts"),
                "record_key": record.get("record_key"),
                "station_id": record.get("station_id"),
                "charger_id": record.get("charger_id"),
                "connector_id": record.get("connector_id"),
                "status": record.get("status"),
                "message_type": record.get("message_type"),
                "payload_json": record.get("payload_json"),
                "payload_sha1": record.get("payload_sha1"),
            }
            event["derived"] = self._compute_derived(event, received_dt)

            record_key = str(event["record_key"] or "")
            if record_key:
                self.current_status[record_key] = event

            by_file[self._raw_file_path(received_dt)].append(event)

        for path, items in by_file.items():
            path.parent.mkdir(parents=True, exist_ok=True)
            with path.open("a", encoding="utf-8") as fh:
                for item in items:
                    fh.write(json.dumps(item, ensure_ascii=False, separators=(",", ":")))
                    fh.write("\n")

        return len(records)

    def write_snapshot(self) -> Path:
        now = utc_now()
        path = self._snapshot_file_path(now)
        path.parent.mkdir(parents=True, exist_ok=True)

        payload = {
            "snapshot_at": iso_utc(now),
            "count": len(self.current_status),
            "records": list(self.current_status.values()),
        }

        with path.open("w", encoding="utf-8") as fh:
            json.dump(payload, fh, ensure_ascii=False, indent=2)

        return path

