from datetime import datetime, timezone
from pathlib import Path


class GCSBatchUploader:
    def __init__(
        self,
        project_root: Path,
        data_root: str,
        bucket_name: str,
        prefix: str,
        sync_every_minutes: int,
        credentials_json: str,
    ) -> None:
        self.project_root = project_root
        self.data_root = data_root
        self.bucket_name = bucket_name
        self.prefix = prefix.strip("/")
        self.sync_every_seconds = sync_every_minutes * 60
        self.credentials_json = credentials_json
        self.last_sync_at = 0.0

        self.enabled = bool(self.bucket_name)
        self.status_file = self.project_root / self.data_root / "status" / "gcs_sync_status.json"
        self.manifest_file = self.project_root / self.data_root / "status" / "gcs_manifest.json"

        self._client = None
        self._bucket = None

    def _iso_utc_now(self) -> str:
        return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

    def _write_status(
        self,
        result: str,
        message: str,
        files_uploaded: int = 0,
        last_success_at: str | None = None,
        details: str | None = None,
    ) -> None:
        self.status_file.parent.mkdir(parents=True, exist_ok=True)

        existing: dict[str, str] = {}
        if self.status_file.exists():
            try:
                with self.status_file.open("r", encoding="utf-8") as fh:
                    loaded = json.load(fh)
                    if isinstance(loaded, dict):
                        existing = {k: str(v) for k, v in loaded.items()}
            except Exception:
                existing = {}

        payload: dict[str, str | int] = {
            "result": result,
            "message": message,
            "last_attempt_at": self._iso_utc_now(),
            "last_success_at": last_success_at or existing.get("last_success_at", ""),
            "bucket": self.bucket_name,
            "prefix": self.prefix,
            "data_root": self.data_root,
            "files_uploaded": files_uploaded,
        }

        if details:
            payload["details"] = details

        with self.status_file.open("w", encoding="utf-8") as fh:
            json.dump(payload, fh, ensure_ascii=False, indent=2)

    def _load_manifest(self) -> dict[str, dict[str, int]]:
        if not self.manifest_file.exists():
            return {}
        try:
            with self.manifest_file.open("r", encoding="utf-8") as fh:
                loaded = json.load(fh)
                if not isinstance(loaded, dict):
                    return {}
                manifest: dict[str, dict[str, int]] = {}
                for key, value in loaded.items():
                    if isinstance(key, str) and isinstance(value, dict):
                        size = int(value.get("size", 0))
                        mtime_ns = int(value.get("mtime_ns", 0))
                        manifest[key] = {"size": size, "mtime_ns": mtime_ns}
                return manifest
        except Exception:
            return {}

    def _save_manifest(self, manifest: dict[str, dict[str, int]]) -> None:
        self.manifest_file.parent.mkdir(parents=True, exist_ok=True)
        with self.manifest_file.open("w", encoding="utf-8") as fh:
            json.dump(manifest, fh, ensure_ascii=False, indent=2)

    def _build_object_name(self, rel_path: str) -> str:
        rel = rel_path.replace("\\", "/")
        if self.prefix:
            return f"{self.prefix}/{rel}"
        return rel

    def _ensure_bucket(self) -> bool:
        if not self.enabled:
            return False

        if self._bucket is not None:
            return True

        try:
            from google.cloud import storage

            if self.credentials_json:
                self._client = storage.Client.from_service_account_json(self.credentials_json)
            else:
                self._client = storage.Client()
            self._bucket = self._client.bucket(self.bucket_name)
            return True
        except Exception as exc:
            logging.warning("No se pudo inicializar cliente de GCS: %s", exc)
            self._write_status(
                result="error",
                message="No se pudo inicializar cliente de GCS",
                details=str(exc),
            )
            return False

    def _collect_local_files(self) -> list[tuple[Path, str, int, int]]:
        root = self.project_root / self.data_root
        if not root.exists():
            return []

        files: list[tuple[Path, str, int, int]] = []
        for path in root.rglob("*"):
            if not path.is_file():
                continue

            rel = path.relative_to(root).as_posix()
            if rel.startswith("status/"):
                continue

            stat = path.stat()
            files.append((path, rel, stat.st_size, stat.st_mtime_ns))
        return files

    def maybe_sync(self, force: bool = False) -> None:
        if not self.enabled:
            return

        now = time.time()
        if not force and (now - self.last_sync_at) < self.sync_every_seconds:
            return

        if not self._ensure_bucket():
            self.last_sync_at = now
            return

        try:
            local_files = self._collect_local_files()
            current_manifest = self._load_manifest()
            next_manifest: dict[str, dict[str, int]] = {}
            files_to_upload: list[tuple[Path, str, int, int]] = []

            for abs_path, rel_path, size, mtime_ns in local_files:
                signature = {"size": size, "mtime_ns": mtime_ns}
                next_manifest[rel_path] = signature
                if current_manifest.get(rel_path) != signature:
                    files_to_upload.append((abs_path, rel_path, size, mtime_ns))

            if not files_to_upload:
                self._write_status(
                    result="noop",
                    message="No habia archivos nuevos o modificados para subir a GCS",
                    files_uploaded=0,
                )
                self.last_sync_at = now
                return

            uploaded = 0
            for abs_path, rel_path, _, _ in files_to_upload:
                object_name = self._build_object_name(rel_path)
                blob = self._bucket.blob(object_name)
                content_type, _ = mimetypes.guess_type(abs_path.name)
                blob.upload_from_filename(
                    str(abs_path),
                    content_type=content_type or "application/octet-stream",
                )
                uploaded += 1

            self._save_manifest(next_manifest)
            self._write_status(
                result="ok",
                message="Sincronizacion a GCS completada",
                files_uploaded=uploaded,
                last_success_at=self._iso_utc_now(),
            )
            logging.info("Sync GCS completada: %s archivo(s) subidos", uploaded)
        except Exception as exc:
            logging.warning("Sync GCS fallida: %s", exc)
            self._write_status(
                result="error",
                message="Sync GCS fallida",
                details=str(exc),
            )
        finally:
            self.last_sync_at = now

from __future__ import annotations

import json
import logging
from datetime import datetime, timedelta, timezone
from pathlib import Path


class LocalPreviousDayCleaner:
    def __init__(
        self,
        project_root: Path,
        data_root: str,
        enabled: bool,
    ) -> None:
        self.project_root = project_root
        self.data_root = data_root
        self.enabled = enabled
        self.base_dir = (self.project_root / self.data_root).resolve()
        self.status_file = self.base_dir / "status" / "local_cleanup_status.json"
        self.last_cleaned_day = ""

    def _iso_utc_now(self) -> str:
        return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")

    def _write_status(self, result: str, message: str, deleted_paths: list[str] | None = None) -> None:
        self.status_file.parent.mkdir(parents=True, exist_ok=True)
        payload: dict[str, object] = {
            "result": result,
            "message": message,
            "last_attempt_at": self._iso_utc_now(),
            "data_root": self.data_root,
        }
        if deleted_paths:
            payload["deleted_paths"] = deleted_paths
        with self.status_file.open("w", encoding="utf-8") as fh:
            json.dump(payload, fh, ensure_ascii=False, indent=2)

    def _target_day(self) -> datetime:
        return datetime.now(timezone.utc) - timedelta(days=1)

    def _target_dirs(self, dt: datetime) -> list[Path]:
        yyyy = dt.strftime("%Y")
        mm = dt.strftime("%m")
        dd = dt.strftime("%d")
        return [
            self.base_dir / "raw" / yyyy / mm / dd,
            self.base_dir / "snapshots" / yyyy / mm / dd,
        ]

    def maybe_cleanup(self, force: bool = False) -> None:
        if not self.enabled:
            return

        target_day = self._target_day().strftime("%Y-%m-%d")
        if not force and self.last_cleaned_day == target_day:
            return

        deleted_paths: list[str] = []

        try:
            for directory in self._target_dirs(self._target_day()):
                if not directory.exists():
                    continue

                rel_path = directory.relative_to(self.base_dir).as_posix()
                for child in directory.rglob("*"):
                    if child.is_file():
                        child.unlink(missing_ok=True)

                for child_dir in sorted(
                    (d for d in directory.rglob("*") if d.is_dir()),
                    key=lambda item: len(item.parts),
                    reverse=True,
                ):
                    child_dir.rmdir()

                directory.rmdir()
                deleted_paths.append(rel_path)

            if deleted_paths:
                logging.info("Limpieza local completada para %s: %s", target_day, ", ".join(deleted_paths))
                self._write_status(
                    result="ok",
                    message=f"Se borraron carpetas locales del dia anterior ({target_day})",
                    deleted_paths=deleted_paths,
                )
            else:
                self._write_status(
                    result="noop",
                    message=f"No habia carpetas del dia anterior para borrar ({target_day})",
                )
        except Exception as exc:
            logging.warning("Limpieza local fallida: %s", exc)
            self._write_status(
                result="error",
                message=f"Limpieza local fallida para {target_day}",
                deleted_paths=deleted_paths,
            )
            return

        self.last_cleaned_day = target_day

CREATE TABLE IF NOT EXISTS raw_events (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    received_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    source_ts TEXT NULL,
    record_key VARCHAR(255) NOT NULL,
    station_id VARCHAR(255) NULL,
    charger_id VARCHAR(255) NULL,
    connector_id VARCHAR(255) NULL,
    status VARCHAR(255) NULL,
    message_type VARCHAR(255) NULL,
    payload_sha1 VARCHAR(40) NOT NULL,
    payload_json JSONB NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_raw_events_received_at ON raw_events (received_at);
CREATE INDEX IF NOT EXISTS idx_raw_events_source_ts ON raw_events (source_ts);
CREATE INDEX IF NOT EXISTS idx_raw_events_record_key ON raw_events (record_key);
CREATE INDEX IF NOT EXISTS idx_raw_events_status ON raw_events (status);
CREATE INDEX IF NOT EXISTS idx_raw_events_message_type ON raw_events (message_type);
CREATE INDEX IF NOT EXISTS idx_raw_events_payload_sha1 ON raw_events (payload_sha1);
CREATE INDEX IF NOT EXISTS idx_raw_events_payload_json_gin ON raw_events USING GIN (payload_json);

CREATE TABLE IF NOT EXISTS current_status (
    record_key VARCHAR(255) PRIMARY KEY,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    source_ts TEXT NULL,
    station_id VARCHAR(255) NULL,
    charger_id VARCHAR(255) NULL,
    connector_id VARCHAR(255) NULL,
    status VARCHAR(255) NULL,
    message_type VARCHAR(255) NULL,
    payload_sha1 VARCHAR(40) NOT NULL,
    payload_json JSONB NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_current_status_updated_at ON current_status (updated_at);
CREATE INDEX IF NOT EXISTS idx_current_status_status ON current_status (status);
CREATE INDEX IF NOT EXISTS idx_current_status_payload_json_gin ON current_status USING GIN (payload_json);

CREATE TABLE IF NOT EXISTS snapshots (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    snapshot_ts TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    record_key VARCHAR(255) NOT NULL,
    source_ts TEXT NULL,
    station_id VARCHAR(255) NULL,
    charger_id VARCHAR(255) NULL,
    connector_id VARCHAR(255) NULL,
    status VARCHAR(255) NULL,
    message_type VARCHAR(255) NULL,
    payload_sha1 VARCHAR(40) NOT NULL,
    payload_json JSONB NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_snapshots_snapshot_ts ON snapshots (snapshot_ts);
CREATE INDEX IF NOT EXISTS idx_snapshots_record_key ON snapshots (record_key);
CREATE INDEX IF NOT EXISTS idx_snapshots_status ON snapshots (status);
CREATE INDEX IF NOT EXISTS idx_snapshots_payload_json_gin ON snapshots USING GIN (payload_json);

param(
    [string]$ProjectDir = "C:\opt\nobil-postgres-historico",
    [string]$ServiceName = "nobil-postgres-historico",
    [string]$ServiceUser = "nobil"
)

Set-StrictMode -Version Latest
$ErrorActionPreference = "Stop"

function Test-IsAdmin {
    $identity = [Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object Security.Principal.WindowsPrincipal($identity)
    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function New-RandomPassword {
    $bytes = New-Object byte[] 24
    [Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($bytes)
    $base = [Convert]::ToBase64String($bytes)
    return "N0bil!" + $base.Replace("=", "A").Replace("+", "B").Replace("/", "C")
}

function Ensure-LogOnAsServiceRight {
    param([Parameter(Mandatory = $true)][string]$Sid)

    $tempCfg = Join-Path $env:TEMP "nobil-secpol.cfg"
    $tempOut = Join-Path $env:TEMP "nobil-secpol-updated.cfg"

    secedit /export /cfg $tempCfg | Out-Null
    $lines = Get-Content -Path $tempCfg

    $updated = $false
    $result = @()
    foreach ($line in $lines) {
        if ($line -match '^SeServiceLogonRight\s*=') {
            if ($line -notmatch [Regex]::Escape("*$Sid")) {
                if ($line.Trim().EndsWith("=")) {
                    $line = "$line*$Sid"
                }
                else {
                    $line = "$line,*$Sid"
                }
            }
            $updated = $true
        }
        $result += $line
    }

    if (-not $updated) {
        $result += "SeServiceLogonRight = *$Sid"
    }

    Set-Content -Path $tempOut -Value $result -Encoding Unicode
    secedit /configure /db secedit.sdb /cfg $tempOut /areas USER_RIGHTS | Out-Null
}

if (-not (Test-IsAdmin)) {
    throw "Ejecuta este script en PowerShell como Administrador."
}

$sourceDir = Resolve-Path (Join-Path $PSScriptRoot "..")
if (-not (Test-Path $ProjectDir)) {
    New-Item -Path $ProjectDir -ItemType Directory -Force | Out-Null
}

# Sincroniza codigo hacia el directorio final.
$robocopyArgs = @(
    "$sourceDir",
    "$ProjectDir",
    "/MIR",
    "/XD", ".git", ".venv", "__pycache__", ".vscode",
    "/R:2",
    "/W:1"
)
$null = & robocopy @robocopyArgs
if ($LASTEXITCODE -gt 7) {
    throw "robocopy fallo con codigo $LASTEXITCODE"
}

if (-not (Get-Command py -ErrorAction SilentlyContinue)) {
    throw "No se encontro Python launcher (py). Instala Python 3.10+ desde python.org."
}

$user = Get-LocalUser -Name $ServiceUser -ErrorAction SilentlyContinue
$servicePassword = [credential removed]
$securePassword = [credential removed] $servicePassword -AsPlainText -Force

if ($null -eq $user) {
    $user = New-LocalUser -Name $ServiceUser -Password $securePassword -PasswordNeverExpires -UserMayNotChangePassword -AccountNeverExpires -Description "Usuario de servicio para NOBIL ingest"
    Add-LocalGroupMember -Group "Users" -Member $ServiceUser
}
else {
    # Se rota password para poder configurar el servicio sin pedir datos manuales.
    $null = net user $ServiceUser $servicePassword
}

Ensure-LogOnAsServiceRight -Sid $user.SID.Value

$venvDir = Join-Path $ProjectDir ".venv"
if (-not (Test-Path $venvDir)) {
    & py -3 -m venv $venvDir
}

$pythonExe = Join-Path $venvDir "Scripts\python.exe"
$pipExe = Join-Path $venvDir "Scripts\pip.exe"

& $pythonExe -m pip install --upgrade pip
& $pipExe install -r (Join-Path $ProjectDir "requirements.txt")

$envPath = Join-Path $ProjectDir ".env"
$envExamplePath = Join-Path $ProjectDir ".env.example"
if (-not (Test-Path $envPath)) {
    Copy-Item -Path $envExamplePath -Destination $envPath -Force
}

$envMap = @{}
Get-Content $envPath | ForEach-Object {
    if ($_ -match '^\s*#' -or $_ -notmatch '=') { return }
    $parts = $_.Split('=', 2)
    $k = $parts[0].Trim()
    $v = $parts[1].Trim()
    $envMap[$k] = $v
}

if (-not $envMap.ContainsKey('NOBIL_API_KEY') -or [string]::IsNullOrWhiteSpace($envMap['NOBIL_API_KEY'])) {
    throw "Falta NOBIL_API_KEY en $envPath"
}
if (-not $envMap.ContainsKey('DATABASE_URL') -or [string]::IsNullOrWhiteSpace($envMap['DATABASE_URL'])) {
    throw "Falta DATABASE_URL en $envPath"
}
if ($envMap['DATABASE_URL'] -notmatch 'sslmode=require') {
    throw "DATABASE_URL debe incluir sslmode=require"
}

$aclUser = "$env:COMPUTERNAME\$ServiceUser"
$null = & icacls $envPath /inheritance:r /grant:r "Administrators:F" "SYSTEM:F" "$aclUser:R"

$binDir = Join-Path $ProjectDir "bin"
if (-not (Test-Path $binDir)) {
    New-Item -Path $binDir -ItemType Directory -Force | Out-Null
}

$nssmExe = Join-Path $binDir "nssm.exe"
if (-not (Test-Path $nssmExe)) {
    $zipPath = Join-Path $env:TEMP "nssm-2.24.zip"
    $extractDir = Join-Path $env:TEMP "nssm-2.24"
    Invoke-WebRequest -Uri "https://nssm.cc/release/nssm-2.24.zip" -OutFile $zipPath
    if (Test-Path $extractDir) {
        Remove-Item -Path $extractDir -Recurse -Force
    }
    Expand-Archive -Path $zipPath -DestinationPath $extractDir
    Copy-Item -Path (Join-Path $extractDir "nssm-2.24\win64\nssm.exe") -Destination $nssmExe -Force
}

$logsDir = Join-Path $ProjectDir "logs"
if (-not (Test-Path $logsDir)) {
    New-Item -Path $logsDir -ItemType Directory -Force | Out-Null
}

$serviceExists = Get-Service -Name $ServiceName -ErrorAction SilentlyContinue
if ($null -eq $serviceExists) {
    & $nssmExe install $ServiceName $pythonExe "-m src.nobil_ingest.main"
}

& $nssmExe set $ServiceName AppDirectory $ProjectDir
& $nssmExe set $ServiceName AppStdout (Join-Path $logsDir "service.out.log")
& $nssmExe set $ServiceName AppStderr (Join-Path $logsDir "service.err.log")
& $nssmExe set $ServiceName AppRotateFiles 1
& $nssmExe set $ServiceName AppRotateOnline 1
& $nssmExe set $ServiceName AppRotateSeconds 86400
& $nssmExe set $ServiceName Start SERVICE_AUTO_START
& $nssmExe set $ServiceName ObjectName ".\$ServiceUser" $servicePassword

$null = & sc.exe failure $ServiceName reset= 0 actions= restart/5000/restart/5000/restart/5000
$null = & sc.exe failureflag $ServiceName 1

Start-Service -Name $ServiceName

Start-Sleep -Seconds 3
$svc = Get-Service -Name $ServiceName
Write-Host "Servicio: $($svc.Name) Estado: $($svc.Status)"
Write-Host "Proyecto: $ProjectDir"
Write-Host "Env: $envPath"
Write-Host "Log out: $(Join-Path $logsDir 'service.out.log')"
Write-Host "Log err: $(Join-Path $logsDir 'service.err.log')"

# Prueba de conectividad y tablas remotas sin exponer secretos.
$verifyCode = @'
import os
from sqlalchemy import create_engine, text
from dotenv import load_dotenv

load_dotenv()
url = os.getenv("DATABASE_URL", "")
if not url:
    raise SystemExit("DATABASE_URL ausente")
engine = create_engine(url, future=True)
with engine.connect() as conn:
    rows = conn.execute(text("""
        SELECT table_name
        FROM information_schema.tables
        WHERE table_schema = 'public'
          AND table_name IN ('raw_events', 'current_status', 'snapshots')
        ORDER BY table_name
    """)).fetchall()
    print("tables=" + ",".join([r[0] for r in rows]))
'@

$verifyPath = Join-Path $env:TEMP "verify_nobil_tables.py"
Set-Content -Path $verifyPath -Value $verifyCode -Encoding UTF8
Push-Location $ProjectDir
& $pythonExe $verifyPath
Pop-Location

Write-Host "Provision Windows completado."
